#include <stdio.h>
#include <stdlib.h>

int gcd_int(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        int *a = (int*)malloc(N * sizeof(int));
        int G = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &a[i]);
            G = (i==0) ? a[i] : gcd_int(G, a[i]);
        }
        int cnt = 0, cur = 0;
        for (int i = 0; i < N; ++i) {
            cur = (cur==0) ? a[i] : gcd_int(cur, a[i]);
            if (cur == G) {
                ++cnt;
                cur = 0;
            }
        }
        printf(cnt >= K ? "YES\n" : "NO\n");
        free(a);
    }
    return 0;
}

